import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"2.5.相貌","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/2.建卡相关/2.5.相貌.md","filePath":"1.基础规则/2.建卡相关/2.5.相貌.md"}'),d={name:"1.基础规则/2.建卡相关/2.5.相貌.md"};function _(l,a,p,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_2-5-相貌",tabindex:"-1"},[s("2.5.相貌 "),e("a",{class:"header-anchor",href:"#_2-5-相貌","aria-label":'Permalink to "2.5.相貌"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001")])])],-1),o('<h1 id="相貌" tabindex="-1">相貌 <a class="header-anchor" href="#相貌" aria-label="Permalink to &quot;相貌&quot;">​</a></h1><p>相貌</p><p>较为特殊的是，建卡风度也会决定人物的初始相貌，人物的初始相貌最高不能超过建卡风度等级。</p><p>相貌是评定一名轮回者长相的关键指标，在建卡相貌基础上每高出5点就会获得1点全检定上的加值。过高的相貌可能会导致轮回者无法在影片中正常行走，相应的，在表现力上，过高的相貌可以让一名轮回者更容易讨得他人欢心（特别是异性）。<br> 相貌大致评级标准：<br> 1-3正常人水平<br> 4-5俊美<br> 6+倾城级</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
